    pub fn compute_layout(&self, surface_width: f32, font_size: f32) -> TabBarLayout
}

// Return type with field names:
pub struct TabBarLayout {
    pub tabs: Vec<TabLayout>,        // left-to-right pill positions
    pub new_tab_button: CloseButtonRect,  // "+" button center + size
    pub bar_height: f32,             // total bar height in pixels
    pub visible: bool,               // false if <2 tabs
}

pub struct TabLayout {
    pub rect: TabRect,       // pill geometry
    pub close: CloseButtonRect, // close button center
    pub text_x: f32,         // left edge of text in pixels
    pub close_visible: bool, // only for active/dirty tabs
    pub info: TabInfo,       // index, title, active, dirty
}

pub struct TabRect {
    pub x: f32, pub y: f32, pub w: f32, pub h: f32,
    pub radius: f32,  // corner radius, capped at h/2
}

pub struct CloseButtonRect {
    pub cx: f32, pub cy: f32, pub size: f32,  // center + square size
}
```

